class InMemoryDatabase:
    """Thread-safe in-memory database for users and sessions."""

    def __init__(self):
        self._users: Dict[str, dict] = {}
        self._tokens: Dict[str, dict] = {}
        self._user_data: Dict[str, dict] = {}
        self._lock = threading.RLock()
        self._seed_data()

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def _seed_data(self):
        """Seed with initial test data."""
        users = [
            {"username": "admin", "email": "admin@example.com",
             "password": "admin123", "full_name": "Admin User"},
            {"username": "john_doe", "email": "john@example.com",
             "password": "password123", "full_name": "John Doe"},
            {"username": "jane_smith", "email": "jane@example.com",
             "password": "password456", "full_name": "Jane Smith"},
        ]
        for user in users:
            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": user["username"],
                "email": user["email"],
                "password_hash": self._hash_password(user["password"]),
                "full_name": user["full_name"],
                "created_at": int(time.time()),
            }
            self._user_data[user_id] = {
                "profile": {"bio": f"Bio for {user['full_name']}", "avatar": "default.png"},
                "settings": {"theme": "dark", "notifications": True, "language": "en"},
                "activity": [
                    {"action": "login", "timestamp": int(time.time()) - 3600},
                    {"action": "profile_update", "timestamp": int(time.time()) - 1800},
                ],
            }
        logging.info(f"Database seeded with {len(self._users)} users")

    def register_user(self, username: str, email: str, password: str, full_name: str) -> tuple:
        with self._lock:
            for user in self._users.values():
                if user["username"] == username:
                    return None, "Username already exists"
                if user["email"] == email:
                    return None, "Email already registered"

            user_id = str(uuid.uuid4())
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "full_name": full_name,
                "created_at": int(time.time()),
            }
            self._user_data[user_id] = {
                "profile": {"bio": "", "avatar": "default.png"},
                "settings": {"theme": "light", "notifications": True, "language": "en"},
                "activity": [],
            }
            return user_id, "Registration successful"

    def authenticate(self, username: str, password: str) -> tuple:
        with self._lock:
            password_hash = self._hash_password(password)
            for user in self._users.values():
                if user["username"] == username and user["password_hash"] == password_hash:
                    token = secrets.token_hex(32)
                    self._tokens[token] = {
                        "user_id": user["user_id"],
                        "username": user["username"],
                        "created_at": int(time.time()),
                        "expires_at": int(time.time()) + 3600,  # 1 hour expiry
                    }
                    return token, user
            return None, None

    def validate_token(self, token: str) -> Optional[dict]:
        with self._lock:
            token_data = self._tokens.get(token)
            if token_data and token_data["expires_at"] > int(time.time()):
                return token_data
            if token_data:
                del self._tokens[token]
            return None

    def invalidate_token(self, token: str) -> bool:
        with self._lock:
            if token in self._tokens:
                del self._tokens[token]
                return True
            return False

    def get_user(self, user_id: str) -> Optional[dict]:
        with self._lock:
            return self._users.get(user_id)

    def list_users(self, page: int, page_size: int) -> tuple:
        with self._lock:
            all_users = list(self._users.values())
            total = len(all_users)
            start = page * page_size
            end = start + page_size
            return all_users[start:end], total

    def get_user_data(self, user_id: str, data_type: str = None) -> Optional[dict]:
        with self._lock:
            data = self._user_data.get(user_id)
            if data and data_type:
                return {data_type: data.get(data_type)}
            return data


