# ==================== Server ====================

class MicroservicesServer:
    """gRPC server for microservices."""

    def __init__(self, host: str = "localhost", port: int = 50051, max_workers: int = 10):
        self.host = host
        self.port = port
        self.max_workers = max_workers
        self.server = None
        self.logger = logging.getLogger("Server")

    def start(self):
        if not GRPC_AVAILABLE:
            self.logger.error("gRPC not available. Install with: pip install grpcio grpcio-tools")
            return

        self.server = grpc.server(
            futures.ThreadPoolExecutor(max_workers=self.max_workers),
            options=[
                ("grpc.max_send_message_length", 50 * 1024 * 1024),
                ("grpc.max_receive_message_length", 50 * 1024 * 1024),
                ("grpc.keepalive_time_ms", 10000),
                ("grpc.keepalive_timeout_ms", 5000),
                ("grpc.keepalive_permit_without_calls", True),
                ("grpc.http2.max_pings_without_data", 0),
                ("grpc.http2.min_time_between_pings_ms", 10000),
                ("grpc.http2.min_ping_interval_without_data_ms", 5000),
            ],
            interceptors=[LoggingInterceptor()],
        )

        if STUBS_AVAILABLE:
            service_pb2_grpc.add_AuthServiceServicer_to_server(
                AuthServiceServicer(), self.server
            )
            service_pb2_grpc.add_DataServiceServicer_to_server(
                DataServiceServicer(), self.server
            )
            self.logger.info("Registered AuthService and DataService (compiled stubs)")
        else:
            self.logger.warning(
                "Proto stubs not compiled. Run compile_proto() first for full gRPC support."
            )
            self.logger.info("Server will start but services need compiled stubs to work.")

        bind_address = f"{self.host}:{self.port}"
        self.server.add_insecure_port(bind_address)
        self.server.start()
        self.logger.info(f"gRPC Server started on {bind_address}")
        self.logger.info(f"Max workers: {self.max_workers}")
        self.logger.info("Press Ctrl+C to stop the server")

    def stop(self, grace: float = 5.0):
        if self.server:
            self.logger.info(f"Shutting down server (grace period: {grace}s)...")
            self.server.stop(grace)
            self.logger.info("Server stopped")

    def wait_for_termination(self):
        if self.server:
            self.server.wait_for_termination()


# ==================== Interceptor ====================

class LoggingInterceptor(grpc.ServerInterceptor if GRPC_AVAILABLE else object):
    """Server interceptor for logging and metrics."""

    def __init__(self):
        self.logger = logging.getLogger("Interceptor")
        self._call_count = 0
        self._lock = threading.Lock()

    def intercept_service(self, continuation, handler_call_details):
        with self._lock:
            self._call_count += 1
            count = self._call_count

        method = handler_call_details.method
        metadata = dict(handler_call_details.invocation_metadata or [])

        self.logger.info(
            f"[Call #{count}] Method: {method} | "
            f"Peer metadata keys: {list(metadata.keys())}"
        )

        start_time = time.time()
        response = continuation(handler_call_details)
        elapsed = time.time() - start_time

        self.logger.info(f"[Call #{count}] Completed in {elapsed:.4f}s")
        return response


